import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetShotInfoNode(BaseNode):
    name = "Prism: Get Shot Info"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_output("sequence", "string")
        self.add_output("shot_name", "string")
        self.add_output("frame_start", "int")
        self.add_output("frame_end", "int")
        self.add_output("fps", "float")
        self.add_output("entity_path", "string")

    def _get_frame_range(self, core, entity, entity_path):
        for method in ('getEntityFrameRange', 'getShotRange', 'getFrameRange'):
            fn = getattr(core.entities, method, None)
            if not callable(fn):
                continue
            try:
                r = fn(entity)
                if isinstance(r, (list, tuple)) and len(r) >= 2:
                    return int(r[0]), int(r[1])
                if isinstance(r, dict):
                    return (int(r.get('start', r.get('frameStart', 1))),
                            int(r.get('end', r.get('frameEnd', 100))))
            except Exception:
                pass
        if entity_path:
            for cfg_name in ('pipeline.json', 'shot.json'):
                cfg = os.path.join(entity_path, '00_Pipeline', cfg_name)
                if os.path.exists(cfg):
                    try:
                        fr = core.getConfig('globals', 'frameRange', configPath=cfg)
                        if isinstance(fr, (list, tuple)) and len(fr) >= 2:
                            return int(fr[0]), int(fr[1])
                    except Exception:
                        pass
        return 1, 100

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        defaults = {'sequence': '', 'shot_name': '', 'frame_start': 1,
                    'frame_end': 100, 'fps': 24.0, 'entity_path': ''}
        if core is None:
            self.log_error('No PrismCore found.')
            return defaults
        seq = str(entity.get('sequence', ''))
        shot = str(entity.get('shot', entity.get('name', '')))
        entity_path = str(entity.get('path', ''))
        frame_start, frame_end = self._get_frame_range(core, entity, entity_path)
        fps = 24.0
        try:
            fps = float(core.projects.getFps() or 24.0)
        except Exception:
            pass
        self.log_info(f'Shot {seq}/{shot} | frames {frame_start}-{frame_end} | {fps}fps | path={entity_path}')
        return {'sequence': seq, 'shot_name': shot, 'frame_start': frame_start,
                'frame_end': frame_end, 'fps': fps, 'entity_path': entity_path}

def register_node():
    return PrismGetShotInfoNode
